def solve():
    s = input().strip()
    n = len(s)
    has_X = 'X' in s
    x_range = range(10) if has_X else range(1)

    count = 0
    for xv in x_range:
        # Fill X positions
        t = list(s)
        for i in range(n):
            if t[i] == 'X':
                t[i] = str(xv)
        # Now enumerate all _ combinations
        blanks = [i for i in range(n) if t[i] == '_']
        from itertools import product
        for vals in product('0123456789', repeat=len(blanks)):
            u = t[:]
            for i, v in zip(blanks, vals):
                u[i] = v
            num_str = ''.join(u)
            if n > 1 and num_str[0] == '0':
                continue
            if int(num_str) % 25 == 0:
                count += 1
    print(count)

solve()
